-- 2021010101 30人
INSERT INTO student_info (student_no, real_name, gender, id_card, nation, native_place, phone, email, college_id, major_id, class_id, enrollment_time, student_status)
SELECT
  CONCAT('2021010101', LPAD(a.id, 2, '0')),
  CONCAT('学生_2021010101_', a.id),
  CASE WHEN a.id%2=0 THEN '男' ELSE '女' END,
  CONCAT('11010119990101', LPAD(a.id+1000, 4, '0')),
  '汉族',
  '北京市',
  CONCAT('1380011', LPAD(a.id+1000, 4, '0')),
  CONCAT('stu_2021010101_', a.id, '@school.com'),
  1, 1, 1, '2021-09-01', '在读'
FROM (SELECT 1 id UNION SELECT 2 UNION SELECT 3 UNION SELECT 4 UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9 UNION SELECT 10
      UNION SELECT 11 UNION SELECT 12 UNION SELECT 13 UNION SELECT 14 UNION SELECT 15 UNION SELECT 16 UNION SELECT 17 UNION SELECT 18 UNION SELECT 19 UNION SELECT 20
      UNION SELECT 21 UNION SELECT 22 UNION SELECT 23 UNION SELECT 24 UNION SELECT 25 UNION SELECT 26 UNION SELECT 27 UNION SELECT 28 UNION SELECT 29 UNION SELECT 30) a;

